1	export interface QuoteInput {
2	  items: { type: string }[];
3	}
4	
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	export function quote(input: QuoteInput): number {
17	  const basePremiumTotal = input.items.reduce(
18	    (sum, item) => sum + BASE_PREMIUMS[item.type],
19	    0,
20	  );
21	  return basePremiumTotal + PROCESSING_FEE;
22	}
23	
24	export function claim(): number {
25	  return undefined as unknown as number;
26	}
